"""
MKT Christ Commentary — Hosea chapters 13–14
Run: python3 scripts/zc-christ-hosea-13-14.py

Key Christological nodes:
  13:4  — 'no savior except me' → Acts 4:12 (salvation in no other name)
  13:14 — 'ransom from the grave / redeem from death' → 1 Cor 15:55 (Paul's resurrection taunt)
  14:2  — 'fruit of our lips' → Heb 13:15 (sacrifice of praise, mediated by Christ)
  14:4  — 'I will love them freely' → 1 John 4:10 / Rom 5:8 (unconditional grace/propitiation)
  14:8  — 'your fruit comes from me' → John 15:5 (apart from me you can do nothing)
  14:9  — wisdom conclusion + stumbling → Rom 9:32-33 / 1 Cor 1:24 (Christ the wisdom of God)

Format: standard mkt-christ labels —
  A theme: / A shadow: / A type: / A revelation of God: / A direct anticipation:
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HOSEA = {
  "13": {
    "1": "<p>A theme: When Ephraim spoke, the nations trembled — then came guilt through Baal and he died. The fall from greatness through covenant betrayal is the structure of Adam's fall projected onto the nation. Israel's original exaltation (trembling nations) is like humanity's original dominion (Gen 1:28); both are forfeited through idolatry/disobedience. Christ reverses the pattern: as the second Adam he succeeds where Israel-as-Adam failed, and the nations no longer tremble in judgment but stream in repentance (Rev 21:24).</p>",
    "2": "<p>A theme: They sin more and more, making molten images from their silver — those who kiss the golden calves are worshipping the product of their own hands. The escalating logic of idolatry (each sin makes the next easier) is the pattern Paul describes in Romans 1:21-25: exchanging the glory of God for images made like mortal creatures. The idol-kisser is the inverse of the prodigal who returns to the father's embrace (Luke 15:20); both acts are expressions of the same fundamental loyalty — who or what you turn toward defines your life.</p>",
    "3": "<p>A shadow: Therefore they will be like morning mist, like the early dew that disappears, like chaff swept from a threshing floor. The four images of evanescence — mist, dew, chaff, smoke — are YHWH's verdict on covenant rebellion's staying power. The permanent is YHWH's steadfast love (Lam 3:22: it never ceases); the transient is everything that substitutes for him. The beatitudes invert this: those who are poor in spirit (those who have stopped grasping) inherit the eternal kingdom; those who accumulate like the rich fool are told their soul is required tonight (Luke 12:20).</p>",
    "4": "<p>A revelation of God: 'I am the LORD your God from the land of Egypt, and you shall acknowledge no god but me; there is no savior except me.' The Exodus identity and the absolute sole-savior claim are the OT's most concentrated expression of YHWH's exclusive salvific sovereignty. Peter's declaration in Acts 4:12 — 'there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved' — is the NT form of the same claim: the name is now identified as Jesus, the one through whom YHWH's sole-savior identity is enacted in history. Hosea 13:4 and Acts 4:12 are the same theological claim across the two testaments.</p>",
    "5": "<p>A revelation of God: 'I knew you in the wilderness, in a land of scorching heat.' The intimate covenant-knowledge (<em>yada</em>) of Israel in the wilderness — YHWH knowing his people precisely in the place of deprivation and vulnerability — is the OT form of Christ's shepherding knowledge. 'I know my own and my own know me' (John 10:14); the Good Shepherd knows his sheep by name (John 10:3). The scorching wilderness is where YHWH's knowledge is most vivid — not in the comfortable land of plenty where Israel forgot him (v6), but in the barren place where there is nothing but God.</p>",
    "6": "<p>A theme: When I fed them, they were satisfied; when they were satisfied, their hearts grew proud; therefore they forgot me. The prosperity-forgetfulness-pride sequence is the pattern of every falling away from covenant fidelity. Jesus warns against it in the parable of the rich fool (Luke 12:16-21) and in the Sermon on the Mount's treatment of wealth (Matt 6:24-25). The manna miracle that fed Israel in the wilderness became the occasion for golden-calf idolatry (Exod 32) when they arrived at Sinai well-fed; Hosea identifies the same dynamic in the land. Satisfaction without gratitude is the spiritual condition that makes a person spiritually dead while physically alive (Rev 3:17: you say I am rich... but you are wretched).</p>",
    "7": "<p>A revelation of God: 'So I will be to them like a lion; I will lurk like a leopard on the road.' The divine wrath expressed as predatory pursuit is the dark underside of the covenant claim. The same YHWH who leads his people like a shepherd (Ps 23:1) becomes a lion for those who flee from the covenant. The lion-roar that in Hosea 11:10 calls the scattered exiles home here hunts down the apostate. The NT's sober counterpart: 'It is a fearful thing to fall into the hands of the living God' (Heb 10:31); the one who is our Advocate when we confess (1 John 2:1) is the one who judges when we harden (Rev 6:16). Both faces belong to the same holy God.</p>",
    "8": "<p>A theme: I will attack them like a bear robbed of her cubs; I will tear open their chests and devour them. The wild animals as instruments of divine wrath are a consistent covenant-curse motif (Lev 26:22; Deut 32:24). This is the cup of wrath that Christ prayed to have removed (Luke 22:42) — and drank. The tearing open of the chest is the violence of God's judgment against sin; the cross is where that violence is absorbed by the one who had no sin (2 Cor 5:21), so that those who are in him need not face the bear but can say 'no condemnation' (Rom 8:1).</p>",
    "9": "<p>A revelation of God: 'O Israel, you have destroyed yourself; but your help is in me alone.' The paradox of divine grace: Israel is simultaneously the cause of its own destruction and the recipient of the only available help. The two truths coexist — sin destroys, and YHWH alone helps — without one canceling the other. 'Your help is in me alone' is the OT's exclusive-grace declaration that Christ embodies: 'I am the way, and the truth, and the life; no one comes to the Father except through me' (John 14:6). The one who destroys himself by rejecting Christ is in the same position as Ephraim: the destruction is self-inflicted; the sole available help is the one being rejected.</p>",
    "10": "<p>A theme: 'Where is your king now, that he may save you in all your cities? Where are the rulers of whom you said, Give us a king and princes?' YHWH's rhetorical question exposes the bankruptcy of Israel's political messiah-hope. They had demanded a king like the nations (1 Sam 8:5-20) and got a succession of kings who could not save them. The question 'where is your king?' has no satisfying answer under the human monarchy — but finds its answer in the one who is King of kings (Rev 19:16). The messianic king who truly saves in all his cities is the one Hosea's question is preparing the way for.</p>",
    "11": "<p>A theme: 'I gave you a king in my anger, and I took him away in my wrath.' The rise and fall of human kingship under YHWH's sovereign disposal — given in anger, taken in wrath — is the theological commentary on Saul's dynasty (and all the northern kings). The instability of every human throne contrasts with the stability of the one whose throne is established forever (2 Sam 7:16; Ps 89:29). Christ's throne is not given in YHWH's anger or taken in his wrath; it is established through the Father's resurrection of the Son (Acts 2:36: God has made him both Lord and Christ).</p>",
    "12": "<p>A theme: 'The iniquity of Ephraim is stored up; his sin is kept on record.' The divine ledger of stored iniquity — sin that has not been forgiven, debt that has not been cancelled — is the condition Christ addresses in the new covenant. 'I will remember their sins no more' (Jer 31:34; Heb 8:12): the new covenant promise is the erasure of the stored record. 'Nailing it to the cross' — Paul's image of the record of debt cancelled (Col 2:14) — is the NT form of the stored-up iniquity of Hosea 13:12 being cancelled. The ledger is emptied, not because the debt was ignored, but because Christ paid it.</p>",
    "13": "<p>A theme: The pains of childbirth come upon him, but he is an unwise child who does not present himself at the opening of the womb — refusing the new birth at the appointed time. Paul uses birth-pang imagery for both judgment (sudden destruction comes, as labor pains on a pregnant woman, 1 Thess 5:3) and new creation (the whole creation has been groaning together in the pains of childbirth, Rom 8:22). The child who will not be born at the <em>moed</em> (the appointed time) is Israel refusing the kairos of salvation; Jesus's 'the time is fulfilled' (Mark 1:15) is the appointed moment that Israel in Hosea's vision was too unwise to recognize. The refusal of new birth is the refusal of Christ (John 3:3).</p>",
    "14": "<p>A direct anticipation: 'Shall I ransom them from the power of the grave? Shall I redeem them from death? Come, Death, with your plagues! Come, Grave, with your destruction! Compassion is hidden from my eyes.' Paul quotes this verse in the resurrection proclamation: 'O death, where is your victory? O death, where is your sting?' (1 Cor 15:55). The Hosea text is textually ambiguous — the Hebrew allows either divine promise ('I will indeed ransom') or divine taunt against death ('Will I ransom? Let death come!'). Paul reads it as the triumphant defiance that Christ's resurrection makes possible: death's plagues and the grave's destruction are summoned to their own defeat. The cross is where YHWH's ransom (<em>padah</em>) and redemption (<em>ga'al</em>) are paid; the resurrection is where death's taunt is answered. Hosea 13:14 is the OT's anticipatory cry of what Easter declares.</p>",
    "15": "<p>A theme: Though he flourishes among his brothers, an east wind will come — the LORD's wind rising from the wilderness — and his spring will dry up and his fountain run dry. The sirocco blast that destroys the flourishing vine is the judgment that falls on all security not rooted in YHWH. The east wind is the <em>ruach</em> that YHWH controls (Exod 14:21); the same Spirit that preserves his people destroys the idolatrous nation. The treasury and precious things carried to Assyria is the covenant-curse fulfillment (Deut 28:31-42). Christ's warning: 'Everyone who hears these words of mine and does not do them will be like a foolish man who built his house on the sand... great was the fall of it' (Matt 7:26-27). The east wind reveals what foundation was actually built on.</p>",
    "16": "<p>A revelation of God: Samaria's guilt, rebellion against God, and the sword devouring with infants dashed in pieces — the hardest verse in Hosea. This is the extreme end of covenant curse (Deut 28:53-57): the military destruction that follows complete covenant apostasy. The horror of this verse is part of the cup that Christ prayed to have removed (Luke 22:42) — the cup of divine wrath against sin that he drank to its dregs. The prophet Amos describes similar scenes at Gibeah (Amos 1:13); Christ weeps over Jerusalem because the same cup is coming (Luke 19:41-44). The gospel is the offer to escape the judgment Hosea 13:16 describes, through the one who absorbed it (Gal 3:13: Christ redeemed us from the curse of the law by becoming a curse for us).</p>"
  },
  "14": {
    "1": "<p>A theme: 'Return, O Israel, to the LORD your God, for your sins have caused you to stumble.' The opening call of the restoration chapter is the OT's most direct invitation to repentance-as-return (<em>shuv</em>, the same root used throughout Hosea). Jesus's first proclamation echoes this precisely: 'Repent, for the kingdom of heaven is at hand' (Matt 4:17). The stumbling caused by sin is the condition Christ addresses: he is both the cornerstone for those who believe and the stone of stumbling for those who disobey (1 Pet 2:6-8). The call to return assumes that return is possible — that the covenant relationship is not permanently severed — which is the OT's ground for NT repentance.</p>",
    "2": "<p>A theme: 'Take words with you and return to the LORD; say to him, Forgive all our sins and receive us graciously, and we will offer the fruit of our lips.' The prescribed script of repentance — specific words, not vague intentions — is the form that the prayer of return takes. The prodigal son rehearses exactly this kind of scripted repentance before returning to his father (Luke 15:18-19: 'Father, I have sinned against heaven and before you; I am no longer worthy to be called your son'). Hebrews 13:15 cites 'fruit of lips' as the new covenant sacrifice of praise: 'through him [Christ] then let us continually offer up a sacrifice of praise to God, that is, the fruit of lips that acknowledge his name.' The prayer Hosea prescribes is now mediated through Christ.</p>",
    "3": "<p>A theme: 'Assyria will not save us; we will not ride on horses; we will never again say to what our hands have made, You are our god.' The triple renunciation that the restored community pledges — foreign power, military strength, manufactured idols — is the structure of Christian conversion. The one who turns to Christ explicitly rejects every other claim to save: political power cannot save, military might cannot save, the works of human hands cannot save. 'You have been set free from sin and have become servants of God' (Rom 6:22): the freedom from idolatry that Hosea 14:3 prescribes is the freedom Paul describes as the ground of the new life in Christ.</p>",
    "4": "<p>A type: 'I will heal their waywardness; I will love them freely, for my anger has turned away from them.' The divine response to the prayer of return in v2-3: YHWH heals the <em>meshuvah</em> (waywardness/apostasy), loves freely (<em>nedavah</em>, spontaneously, without condition), and turns his anger away. These three movements are the OT form of the atonement dynamic: the love is prior and unconditional ('not that we loved God but that he loved us', 1 John 4:10); the anger is turned away through propitiation ('he sent his Son as the propitiation for our sins', 1 John 4:10); the waywardness is healed through the healing of the Servant (Isa 53:5: 'by his wounds we are healed'). Hosea 14:4 is the OT's concentrated statement of what the cross accomplishes.</p>",
    "5": "<p>A shadow: 'I will be like the dew to Israel; he will blossom like a lily and take root like the cedars of Lebanon.' The renewing dew, the blossoming lily, the deep-rooting cedar — three images of YHWH's restored presence as the source of flourishing. The Spirit 'poured out from on high' (Isa 32:15: 'until the Spirit is poured upon us from on high, and the wilderness becomes a fruitful field') is the NT form of this dew-image. The new creation in Christ (2 Cor 5:17: if anyone is in Christ, he is a new creation) is the blossoming that Hosea's lily images — the old has passed away and the flourishing of restored covenant life has come.</p>",
    "6": "<p>A shadow: 'His branches will spread out; his beauty will be like the olive tree, and his fragrance like that of Lebanon.' The olive tree as the image of covenant restoration — the tree whose branches spread out in blessing — becomes Paul's image for the Gentile inclusion in Romans 11:17-24: wild olive branches grafted into the cultivated olive tree. The Jewish olive tree with its Gentile branches is the restored-and-expanded covenant community that Hosea's olive-tree image anticipates. The fragrance (Ps 45:8; 2 Cor 2:14-15: 'the aroma of Christ') is the NT's image of the witness that the covenant community bears to the world.</p>",
    "7": "<p>A shadow: 'Those who dwell in his shade will flourish again; they will thrive like grain and blossom like the vine; his fragrance will be like the wine of Lebanon.' The paradisial image of the restored community dwelling in YHWH's shade and bearing grain and vine is the OT form of Jesus's vine-and-branches theology (John 15) and the eschatological feast (Matt 8:11: 'many will come from east and west and recline at table with Abraham, Isaac, and Jacob in the kingdom of heaven'). The wine of Lebanon — the best wine — anticipates the messianic wine Jesus produces at Cana (John 2:10: 'you have kept the good wine until now') and the new wine of the kingdom (Matt 26:29).</p>",
    "8": "<p>A direct anticipation: 'Ephraim will say, What do I have to do with idols any longer? I am the one who answers him and watches over him; I am like an evergreen cypress; your fruit comes from me.' The restored Ephraim's renunciation of idols is answered by YHWH's declaration: 'your fruit comes from me.' This is the exact theological claim of John 15: 'I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit, for apart from me you can do nothing' (John 15:5). The cypress that is always green and never withers — life-giving and permanent — is the image of Christ as the source of all fruitfulness. Hosea 14:8 is John 15 in OT form: the fruit of the covenant life comes not from human effort but from remaining connected to the divine life-source.</p>",
    "9": "<p>A revelation of God: 'Who is wise? Let him understand these things. Who is discerning? Let him know them. For the ways of the LORD are right, and the upright walk in them, but transgressors stumble in them.' The wisdom-invitation that closes the book is the same invitation with which Proverbs closes: knowing YHWH's ways is wisdom. The stumbling pattern that the righteous avoid but transgressors fall into is the OT form of the stone-of-stumbling theology: Israel stumbled over Christ because they pursued righteousness by works rather than by faith (Rom 9:32-33: 'they stumbled over the stumbling stone'). The ways of the LORD that are right are concentrated in Christ, 'the wisdom of God' (1 Cor 1:24). Hosea ends with a summons to wisdom — and wisdom, Paul declares, is Christ: 'Christ Jesus, who became to us wisdom from God' (1 Cor 1:30).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'hosea')
    merge_comm(existing, HOSEA)
    save_comm('mkt-christ', 'hosea', existing)
    print('Hosea 13–14 mkt-christ written.')

if __name__ == '__main__':
    main()
